#!/usr/bin/env python3
"""Install redesigned HomeScreen and updated tab icons.
Run from ~/Desktop/BatKnock:  python3 fix_HomeScreen_and_tabs.py
"""
import base64, os, sys
if not os.path.isdir("screens"):
    sys.exit("Run from BatKnock root folder")

HS = ""
APP = ""

with open("screens/HomeScreen.js", "wb") as f:
    f.write(base64.b64decode(HS))
print("✅ screens/HomeScreen.js updated")

with open("App.js", "wb") as f:
    f.write(base64.b64decode(APP))
print("✅ App.js updated")

print()
print("Now run:  npx expo start --clear --lan")
